for item in funding_data:
    funding_map[item['Project_Name']] = {
        'Funding_Source': item['Funding_Source'],
        'Amount': item['Amount']
    }

all_project_names = list(funding_map.keys())
all_project_names.sort(key=len, reverse=True)

